@page "/patients"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject VetClinic.Data.ApplicationDbContext Db
@using Microsoft.EntityFrameworkCore

<PageTitle>Patients</PageTitle>

<h1>Patient Records</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by pet or owner name..."
               @bind="searchTerm" @bind:event="oninput" @bind:after="Search" />
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-primary" @onclick="ShowRegisterForm">
            <i class="bi bi-plus"></i> Register New Patient
        </button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-4">
        <div class="card-header">
            <h5>@(editingPet == null ? "Register New Patient" : "Edit Patient")</h5>
        </div>
        <div class="card-body">
            <EditForm Model="formModel" OnValidSubmit="SavePatient" FormName="patientForm">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <h6>Owner Information</h6>
                <div class="row mb-3">
                    <div class="col-md-4">
                        <label class="form-label">First Name</label>
                        <InputText class="form-control" @bind-Value="formModel.OwnerFirstName" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Last Name</label>
                        <InputText class="form-control" @bind-Value="formModel.OwnerLastName" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Phone</label>
                        <InputText class="form-control" @bind-Value="formModel.OwnerPhone" />
                    </div>
                </div>
                <div class="row mb-3">
                    <div class="col-md-4">
                        <label class="form-label">Email</label>
                        <InputText class="form-control" @bind-Value="formModel.OwnerEmail" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Existing Owner</label>
                        <InputSelect class="form-select" @bind-Value="formModel.ExistingOwnerId">
                            <option value="0">-- New Owner --</option>
                            @foreach (var owner in owners)
                            {
                                <option value="@owner.Id">@owner.FullName</option>
                            }
                        </InputSelect>
                    </div>
                </div>

                <h6>Pet Information</h6>
                <div class="row mb-3">
                    <div class="col-md-3">
                        <label class="form-label">Name</label>
                        <InputText class="form-control" @bind-Value="formModel.PetName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Species</label>
                        <InputSelect class="form-select" @bind-Value="formModel.Species">
                            <option value="">-- Select --</option>
                            <option value="Dog">Dog</option>
                            <option value="Cat">Cat</option>
                            <option value="Bird">Bird</option>
                            <option value="Rabbit">Rabbit</option>
                            <option value="Reptile">Reptile</option>
                            <option value="Other">Other</option>
                        </InputSelect>
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="formModel.Breed" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Sex</label>
                        <InputSelect class="form-select" @bind-Value="formModel.Sex">
                            <option value="">-- Select --</option>
                            <option value="Male">Male</option>
                            <option value="Female">Female</option>
                            <option value="Neutered">Neutered</option>
                            <option value="Spayed">Spayed</option>
                        </InputSelect>
                    </div>
                </div>
                <div class="row mb-3">
                    <div class="col-md-3">
                        <label class="form-label">Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="formModel.DateOfBirth" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Weight (kg)</label>
                        <InputNumber class="form-control" @bind-Value="formModel.WeightKg" />
                    </div>
                </div>

                <button type="submit" class="btn btn-success me-2">Save</button>
                <button type="button" class="btn btn-secondary" @onclick="CancelForm">Cancel</button>
            </EditForm>
        </div>
    </div>
}

<table class="table table-hover">
    <thead>
        <tr><th>Pet Name</th><th>Species</th><th>Breed</th><th>Owner</th><th>Actions</th></tr>
    </thead>
    <tbody>
        @foreach (var pet in filteredPets)
        {
            <tr>
                <td>@pet.Name</td>
                <td>@pet.Species</td>
                <td>@pet.Breed</td>
                <td>@pet.Owner.FullName</td>
                <td>
                    <button class="btn btn-sm btn-outline-primary me-1" @onclick="() => EditPet(pet)">Edit</button>
                    <button class="btn btn-sm btn-outline-info me-1" @onclick="() => ViewHistory(pet)">History</button>
                    <button class="btn btn-sm btn-outline-success" @onclick="() => AddNote(pet)">+ Note</button>
                </td>
            </tr>
        }
    </tbody>
</table>

@if (selectedPet != null)
{
    <div class="card mt-4">
        <div class="card-header d-flex justify-content-between">
            <h5>Medical History - @selectedPet.Name (@selectedPet.Owner.FullName)</h5>
            <button class="btn btn-sm btn-outline-secondary" @onclick="() => selectedPet = null">Close</button>
        </div>
        <div class="card-body">
            @if (showNoteForm)
            {
                <EditForm Model="noteModel" OnValidSubmit="SaveNote" FormName="noteForm">
                    <DataAnnotationsValidator />
                    <div class="row mb-3">
                        <div class="col-md-4">
                            <label class="form-label">Title</label>
                            <InputText class="form-control" @bind-Value="noteModel.Title" />
                        </div>
                        <div class="col-md-4">
                            <label class="form-label">Veterinarian</label>
                            <InputText class="form-control" @bind-Value="noteModel.Veterinarian" />
                        </div>
                        <div class="col-md-4">
                            <label class="form-label">Date</label>
                            <InputDate class="form-control" @bind-Value="noteModel.Date" />
                        </div>
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Description</label>
                        <InputTextArea class="form-control" rows="3" @bind-Value="noteModel.Description" />
                    </div>
                    <button type="submit" class="btn btn-success me-2">Save Note</button>
                    <button type="button" class="btn btn-secondary" @onclick="() => showNoteForm = false">Cancel</button>
                </EditForm>
                <hr />
            }

            @if (selectedPet.TreatmentNotes.Any())
            {
                @foreach (var note in selectedPet.TreatmentNotes.OrderByDescending(n => n.Date))
                {
                    <div class="border-start border-3 border-primary ps-3 mb-3">
                        <strong>@note.Title</strong> <small class="text-muted">@note.Date.ToString("yyyy-MM-dd") | @note.Veterinarian</small>
                        <p class="mb-0">@note.Description</p>
                    </div>
                }
            }
            else
            {
                <p class="text-muted">No medical history recorded yet.</p>
            }
        </div>
    </div>
}

@code {
    private List<VetClinic.Data.Pet> pets = [];
    private List<VetClinic.Data.Pet> filteredPets = [];
    private List<VetClinic.Data.Owner> owners = [];
    private string searchTerm = "";
    private bool showForm;
    private VetClinic.Data.Pet? editingPet;
    private VetClinic.Data.Pet? selectedPet;
    private bool showNoteForm;
    private PatientFormModel formModel = new();
    private NoteFormModel noteModel = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        pets = await Db.Pets.Include(p => p.Owner).Include(p => p.TreatmentNotes).OrderBy(p => p.Name).ToListAsync();
        owners = await Db.Owners.OrderBy(o => o.LastName).ToListAsync();
        Search();
    }

    private void Search()
    {
        if (string.IsNullOrWhiteSpace(searchTerm))
        {
            filteredPets = pets;
        }
        else
        {
            var term = searchTerm.ToLower();
            filteredPets = pets.Where(p =>
                p.Name.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                p.Owner.FullName.Contains(term, StringComparison.OrdinalIgnoreCase)
            ).ToList();
        }
    }

    private void ShowRegisterForm()
    {
        editingPet = null;
        formModel = new PatientFormModel();
        showForm = true;
    }

    private void EditPet(VetClinic.Data.Pet pet)
    {
        editingPet = pet;
        formModel = new PatientFormModel
        {
            ExistingOwnerId = pet.OwnerId,
            OwnerFirstName = pet.Owner.FirstName,
            OwnerLastName = pet.Owner.LastName,
            OwnerPhone = pet.Owner.Phone,
            OwnerEmail = pet.Owner.Email,
            PetName = pet.Name,
            Species = pet.Species,
            Breed = pet.Breed,
            Sex = pet.Sex,
            DateOfBirth = pet.DateOfBirth,
            WeightKg = pet.WeightKg
        };
        showForm = true;
    }

    private async Task SavePatient()
    {
        VetClinic.Data.Owner owner;
        if (formModel.ExistingOwnerId > 0)
        {
            owner = await Db.Owners.FindAsync(formModel.ExistingOwnerId) ?? throw new InvalidOperationException("Owner not found");
            owner.FirstName = formModel.OwnerFirstName;
            owner.LastName = formModel.OwnerLastName;
            owner.Phone = formModel.OwnerPhone;
            owner.Email = formModel.OwnerEmail;
        }
        else
        {
            owner = new VetClinic.Data.Owner
            {
                FirstName = formModel.OwnerFirstName,
                LastName = formModel.OwnerLastName,
                Phone = formModel.OwnerPhone,
                Email = formModel.OwnerEmail
            };
            Db.Owners.Add(owner);
        }

        if (editingPet != null)
        {
            editingPet.Name = formModel.PetName;
            editingPet.Species = formModel.Species;
            editingPet.Breed = formModel.Breed;
            editingPet.Sex = formModel.Sex;
            editingPet.DateOfBirth = formModel.DateOfBirth;
            editingPet.WeightKg = formModel.WeightKg;
            editingPet.Owner = owner;
        }
        else
        {
            var pet = new VetClinic.Data.Pet
            {
                Name = formModel.PetName,
                Species = formModel.Species,
                Breed = formModel.Breed,
                Sex = formModel.Sex,
                DateOfBirth = formModel.DateOfBirth,
                WeightKg = formModel.WeightKg,
                Owner = owner
            };
            Db.Pets.Add(pet);
        }

        await Db.SaveChangesAsync();
        showForm = false;
        await LoadData();
    }

    private void CancelForm() => showForm = false;

    private void ViewHistory(VetClinic.Data.Pet pet)
    {
        selectedPet = pet;
        showNoteForm = false;
    }

    private void AddNote(VetClinic.Data.Pet pet)
    {
        selectedPet = pet;
        showNoteForm = true;
        noteModel = new NoteFormModel { Date = DateOnly.FromDateTime(DateTime.Today) };
    }

    private async Task SaveNote()
    {
        if (selectedPet == null) return;

        var note = new VetClinic.Data.TreatmentNote
        {
            PetId = selectedPet.Id,
            Title = noteModel.Title,
            Description = noteModel.Description,
            Veterinarian = noteModel.Veterinarian,
            Date = noteModel.Date.ToDateTime(TimeOnly.MinValue)
        };
        Db.TreatmentNotes.Add(note);
        await Db.SaveChangesAsync();
        showNoteForm = false;
        await LoadData();
        selectedPet = pets.FirstOrDefault(p => p.Id == selectedPet.Id);
    }

    private class PatientFormModel
    {
        public int ExistingOwnerId { get; set; }

        [System.ComponentModel.DataAnnotations.Required]
        public string OwnerFirstName { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required]
        public string OwnerLastName { get; set; } = "";

        public string? OwnerPhone { get; set; }
        public string? OwnerEmail { get; set; }

        [System.ComponentModel.DataAnnotations.Required]
        public string PetName { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required]
        public string Species { get; set; } = "";

        public string? Breed { get; set; }
        public string? Sex { get; set; }
        public DateOnly? DateOfBirth { get; set; }
        public double? WeightKg { get; set; }
    }

    private class NoteFormModel
    {
        [System.ComponentModel.DataAnnotations.Required]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required]
        public string Description { get; set; } = "";

        public string? Veterinarian { get; set; }
        public DateOnly Date { get; set; } = DateOnly.FromDateTime(DateTime.Today);
    }
}

@page "/appointments"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject VetClinic.Data.ApplicationDbContext Db
@using Microsoft.EntityFrameworkCore

<PageTitle>Appointments</PageTitle>

<h1>Appointment Scheduling</h1>

<div class="row mb-3">
    <div class="col-md-3">
        <label class="form-label">View Date</label>
        <input type="date" class="form-control" @bind="selectedDate" @bind:after="LoadAppointments" />
    </div>
    <div class="col-md-3 d-flex align-items-end">
        <button class="btn btn-primary" @onclick="ShowCreateForm">+ New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-4">
        <div class="card-header">
            <h5>@(editingAppointment == null ? "Schedule Appointment" : "Edit Appointment")</h5>
        </div>
        <div class="card-body">
            <EditForm Model="formModel" OnValidSubmit="SaveAppointment" FormName="appointmentForm">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="row mb-3">
                    <div class="col-md-4">
                        <label class="form-label">Patient</label>
                        <InputSelect class="form-select" @bind-Value="formModel.PetId">
                            <option value="0">-- Select Patient --</option>
                            @foreach (var pet in pets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Veterinarian</label>
                        <InputText class="form-control" @bind-Value="formModel.Veterinarian" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="formModel.Reason" />
                    </div>
                </div>
                <div class="row mb-3">
                    <div class="col-md-3">
                        <label class="form-label">Date</label>
                        <InputDate class="form-control" @bind-Value="formModel.Date" @bind-Value:after="CheckAvailability" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Start Time</label>
                        <InputSelect class="form-select" @bind-Value="formModel.StartTime" @bind-Value:after="CheckAvailability">
                            @foreach (var slot in timeSlots)
                            {
                                <option value="@slot">@slot.ToString("HH:mm")</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Duration (min)</label>
                        <InputSelect class="form-select" @bind-Value="formModel.DurationMinutes">
                            <option value="15">15 min</option>
                            <option value="30">30 min</option>
                            <option value="45">45 min</option>
                            <option value="60">60 min</option>
                        </InputSelect>
                    </div>
                </div>
                <div class="mb-3">
                    <label class="form-label">Notes</label>
                    <InputTextArea class="form-control" rows="2" @bind-Value="formModel.Notes" />
                </div>

                @if (!string.IsNullOrEmpty(availabilityMessage))
                {
                    <div class="alert @(isSlotAvailable ? "alert-success" : "alert-warning") py-2">
                        @availabilityMessage
                    </div>
                }

                <button type="submit" class="btn btn-success me-2" disabled="@(!isSlotAvailable)">Save</button>
                <button type="button" class="btn btn-secondary" @onclick="() => showForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

<h4>Schedule for @selectedDate.ToString("dddd, MMMM d, yyyy")</h4>

<div class="row">
    <div class="col-md-8">
        <table class="table table-bordered">
            <thead class="table-light">
                <tr><th style="width:120px">Time</th><th>Patient</th><th>Reason</th><th>Vet</th><th>Status</th><th>Actions</th></tr>
            </thead>
            <tbody>
                @if (dayAppointments.Any())
                {
                    @foreach (var apt in dayAppointments)
                    {
                        <tr class="@GetRowClass(apt.Status)">
                            <td>@apt.StartTime.ToString("HH:mm")–@apt.EndTime.ToString("HH:mm")</td>
                            <td>@apt.Pet.Name</td>
                            <td>@apt.Reason</td>
                            <td>@apt.Veterinarian</td>
                            <td><span class="badge bg-@GetStatusColor(apt.Status)">@apt.Status</span></td>
                            <td>
                                @if (apt.Status == VetClinic.Data.AppointmentStatus.Scheduled)
                                {
                                    <button class="btn btn-sm btn-outline-primary me-1" @onclick="() => Reschedule(apt)">Reschedule</button>
                                    <button class="btn btn-sm btn-outline-success me-1" @onclick="() => Complete(apt)">Complete</button>
                                    <button class="btn btn-sm btn-outline-danger" @onclick="() => Cancel(apt)">Cancel</button>
                                }
                            </td>
                        </tr>
                    }
                }
                else
                {
                    <tr><td colspan="6" class="text-center text-muted">No appointments for this day.</td></tr>
                }
            </tbody>
        </table>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-header"><h6>Available Slots</h6></div>
            <div class="card-body">
                @foreach (var slot in GetAvailableSlots())
                {
                    <span class="badge bg-success me-1 mb-1">@slot.ToString("HH:mm")</span>
                }
                @if (!GetAvailableSlots().Any())
                {
                    <span class="text-muted">No available slots.</span>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private DateTime selectedDate = DateTime.Today;
    private List<VetClinic.Data.Appointment> dayAppointments = [];
    private List<VetClinic.Data.Pet> pets = [];
    private bool showForm;
    private VetClinic.Data.Appointment? editingAppointment;
    private AppointmentFormModel formModel = new();
    private string availabilityMessage = "";
    private bool isSlotAvailable = true;

    private static readonly TimeOnly clinicOpen = new(8, 0);
    private static readonly TimeOnly clinicClose = new(18, 0);
    private List<TimeOnly> timeSlots = [];

    protected override async Task OnInitializedAsync()
    {
        GenerateTimeSlots();
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        await LoadAppointments();
    }

    private void GenerateTimeSlots()
    {
        timeSlots = [];
        var current = clinicOpen;
        while (current < clinicClose)
        {
            timeSlots.Add(current);
            current = current.AddMinutes(30);
        }
    }

    private async Task LoadAppointments()
    {
        dayAppointments = await Db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime.Date == selectedDate.Date)
            .OrderBy(a => a.StartTime)
            .ToListAsync();
    }

    private void ShowCreateForm()
    {
        editingAppointment = null;
        formModel = new AppointmentFormModel
        {
            Date = DateOnly.FromDateTime(selectedDate),
            StartTime = clinicOpen,
            DurationMinutes = 30
        };
        showForm = true;
        availabilityMessage = "";
        isSlotAvailable = true;
    }

    private void Reschedule(VetClinic.Data.Appointment apt)
    {
        editingAppointment = apt;
        formModel = new AppointmentFormModel
        {
            PetId = apt.PetId,
            Date = DateOnly.FromDateTime(apt.StartTime),
            StartTime = TimeOnly.FromDateTime(apt.StartTime),
            DurationMinutes = (int)(apt.EndTime - apt.StartTime).TotalMinutes,
            Reason = apt.Reason,
            Veterinarian = apt.Veterinarian ?? "",
            Notes = apt.Notes
        };
        showForm = true;
        isSlotAvailable = true;
        availabilityMessage = "";
    }

    private async Task Complete(VetClinic.Data.Appointment apt)
    {
        apt.Status = VetClinic.Data.AppointmentStatus.Completed;
        await Db.SaveChangesAsync();
        await LoadAppointments();
    }

    private async Task Cancel(VetClinic.Data.Appointment apt)
    {
        apt.Status = VetClinic.Data.AppointmentStatus.Cancelled;
        await Db.SaveChangesAsync();
        await LoadAppointments();
    }

    private async Task CheckAvailability()
    {
        var start = formModel.Date.ToDateTime(formModel.StartTime);
        var end = start.AddMinutes(formModel.DurationMinutes);

        var conflicts = await Db.Appointments
            .Where(a => a.StartTime.Date == start.Date
                && a.Status == VetClinic.Data.AppointmentStatus.Scheduled
                && a.StartTime < end && a.EndTime > start
                && (editingAppointment == null || a.Id != editingAppointment.Id))
            .CountAsync();

        if (conflicts > 0)
        {
            isSlotAvailable = false;
            availabilityMessage = $"⚠️ Conflict: {conflicts} existing appointment(s) overlap this time slot.";
        }
        else
        {
            isSlotAvailable = true;
            availabilityMessage = "✓ Time slot is available.";
        }
    }

    private async Task SaveAppointment()
    {
        var start = formModel.Date.ToDateTime(formModel.StartTime);
        var end = start.AddMinutes(formModel.DurationMinutes);

        if (editingAppointment != null)
        {
            editingAppointment.PetId = formModel.PetId;
            editingAppointment.StartTime = start;
            editingAppointment.EndTime = end;
            editingAppointment.Reason = formModel.Reason;
            editingAppointment.Veterinarian = formModel.Veterinarian;
            editingAppointment.Notes = formModel.Notes;
        }
        else
        {
            var apt = new VetClinic.Data.Appointment
            {
                PetId = formModel.PetId,
                StartTime = start,
                EndTime = end,
                Reason = formModel.Reason,
                Veterinarian = formModel.Veterinarian,
                Notes = formModel.Notes,
                Status = VetClinic.Data.AppointmentStatus.Scheduled
            };
            Db.Appointments.Add(apt);
        }

        await Db.SaveChangesAsync();
        showForm = false;
        selectedDate = formModel.Date.ToDateTime(TimeOnly.MinValue);
        await LoadAppointments();
    }

    private List<TimeOnly> GetAvailableSlots()
    {
        var available = new List<TimeOnly>();
        foreach (var slot in timeSlots)
        {
            var slotStart = selectedDate.Date + slot.ToTimeSpan();
            var slotEnd = slotStart.AddMinutes(30);
            var hasConflict = dayAppointments.Any(a =>
                a.Status == VetClinic.Data.AppointmentStatus.Scheduled &&
                a.StartTime < slotEnd && a.EndTime > slotStart);
            if (!hasConflict)
                available.Add(slot);
        }
        return available;
    }

    private string GetStatusColor(VetClinic.Data.AppointmentStatus status) => status switch
    {
        VetClinic.Data.AppointmentStatus.Scheduled => "primary",
        VetClinic.Data.AppointmentStatus.Completed => "success",
        VetClinic.Data.AppointmentStatus.Cancelled => "secondary",
        _ => "light"
    };

    private string GetRowClass(VetClinic.Data.AppointmentStatus status) => status switch
    {
        VetClinic.Data.AppointmentStatus.Cancelled => "table-secondary text-decoration-line-through",
        VetClinic.Data.AppointmentStatus.Completed => "table-success",
        _ => ""
    };

    private class AppointmentFormModel
    {
        [System.ComponentModel.DataAnnotations.Range(1, int.MaxValue, ErrorMessage = "Please select a patient.")]
        public int PetId { get; set; }

        public DateOnly Date { get; set; } = DateOnly.FromDateTime(DateTime.Today);
        public TimeOnly StartTime { get; set; } = new(9, 0);
        public int DurationMinutes { get; set; } = 30;

        [System.ComponentModel.DataAnnotations.Required]
        public string Reason { get; set; } = "";

        public string? Veterinarian { get; set; }
        public string? Notes { get; set; }
    }
}

@page "/billing"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject VetClinic.Data.ApplicationDbContext Db
@using Microsoft.EntityFrameworkCore

<PageTitle>Billing</PageTitle>

<h1>Billing & Payments</h1>

<ul class="nav nav-tabs mb-3">
    <li class="nav-item">
        <button class="nav-link @(activeTab == "invoices" ? "active" : "")" @onclick='() => activeTab = "invoices"'>Invoices</button>
    </li>
    <li class="nav-item">
        <button class="nav-link @(activeTab == "payments" ? "active" : "")" @onclick='() => activeTab = "payments"'>Payment History</button>
    </li>
</ul>

@if (activeTab == "invoices")
{
    <div class="mb-3">
        <button class="btn btn-primary" @onclick="ShowCreateInvoice">+ New Invoice</button>
    </div>

    @if (showInvoiceForm)
    {
        <div class="card mb-4">
            <div class="card-header"><h5>Create Invoice</h5></div>
            <div class="card-body">
                <EditForm Model="invoiceModel" OnValidSubmit="SaveInvoice" FormName="invoiceForm">
                    <DataAnnotationsValidator />
                    <ValidationSummary class="text-danger" />

                    <div class="row mb-3">
                        <div class="col-md-4">
                            <label class="form-label">Patient</label>
                            <InputSelect class="form-select" @bind-Value="invoiceModel.PetId">
                                <option value="0">-- Select Patient --</option>
                                @foreach (var pet in pets)
                                {
                                    <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
                                }
                            </InputSelect>
                        </div>
                        <div class="col-md-8">
                            <label class="form-label">Description</label>
                            <InputText class="form-control" @bind-Value="invoiceModel.Description" />
                        </div>
                    </div>

                    <h6>Line Items</h6>
                    @for (int i = 0; i < invoiceModel.LineItems.Count; i++)
                    {
                        var idx = i;
                        <div class="row mb-2">
                            <div class="col-md-7">
                                <input class="form-control" placeholder="Description" @bind="invoiceModel.LineItems[idx].Description" />
                            </div>
                            <div class="col-md-3">
                                <input type="number" step="0.01" class="form-control" placeholder="Amount" @bind="invoiceModel.LineItems[idx].Amount" />
                            </div>
                            <div class="col-md-2">
                                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => invoiceModel.LineItems.RemoveAt(idx)">Remove</button>
                            </div>
                        </div>
                    }
                    <button type="button" class="btn btn-outline-secondary btn-sm mb-3" @onclick="AddLineItem">+ Add Line Item</button>

                    <div class="mb-3">
                        <strong>Total: @invoiceModel.LineItems.Sum(li => li.Amount).ToString("C")</strong>
                    </div>

                    <button type="submit" class="btn btn-success me-2">Create Invoice</button>
                    <button type="button" class="btn btn-secondary" @onclick="() => showInvoiceForm = false">Cancel</button>
                </EditForm>
            </div>
        </div>
    }

    <table class="table table-hover">
        <thead>
            <tr><th>#</th><th>Date</th><th>Patient</th><th>Description</th><th>Total</th><th>Paid</th><th>Balance</th><th>Status</th><th>Actions</th></tr>
        </thead>
        <tbody>
            @foreach (var inv in invoices)
            {
                <tr>
                    <td>@inv.Id</td>
                    <td>@inv.IssuedDate.ToString("yyyy-MM-dd")</td>
                    <td>@inv.Pet.Name</td>
                    <td>@inv.Description</td>
                    <td>@inv.Total.ToString("C")</td>
                    <td>@inv.AmountPaid.ToString("C")</td>
                    <td>@inv.Balance.ToString("C")</td>
                    <td>
                        @if (inv.IsPaid)
                        {
                            <span class="badge bg-success">Paid</span>
                        }
                        else
                        {
                            <span class="badge bg-warning">Outstanding</span>
                        }
                    </td>
                    <td>
                        @if (!inv.IsPaid)
                        {
                            <button class="btn btn-sm btn-outline-success" @onclick="() => ShowPaymentForm(inv)">Record Payment</button>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>

    @if (showPayForm && selectedInvoice != null)
    {
        <div class="card mb-4">
            <div class="card-header"><h5>Record Payment for Invoice #@selectedInvoice.Id</h5></div>
            <div class="card-body">
                <EditForm Model="paymentModel" OnValidSubmit="SavePayment" FormName="paymentForm">
                    <DataAnnotationsValidator />
                    <div class="row mb-3">
                        <div class="col-md-3">
                            <label class="form-label">Amount (Balance: @selectedInvoice.Balance.ToString("C"))</label>
                            <InputNumber class="form-control" @bind-Value="paymentModel.Amount" />
                        </div>
                        <div class="col-md-3">
                            <label class="form-label">Method</label>
                            <InputSelect class="form-select" @bind-Value="paymentModel.Method">
                                @foreach (var method in Enum.GetValues<VetClinic.Data.PaymentMethod>())
                                {
                                    <option value="@method">@method</option>
                                }
                            </InputSelect>
                        </div>
                        <div class="col-md-3">
                            <label class="form-label">Reference</label>
                            <InputText class="form-control" @bind-Value="paymentModel.Reference" />
                        </div>
                        <div class="col-md-3">
                            <label class="form-label">Date</label>
                            <InputDate class="form-control" @bind-Value="paymentModel.Date" />
                        </div>
                    </div>
                    <button type="submit" class="btn btn-success me-2">Process Payment</button>
                    <button type="button" class="btn btn-secondary" @onclick="() => showPayForm = false">Cancel</button>
                </EditForm>
            </div>
        </div>
    }
}
else
{
    <h4>Payment History</h4>
    <table class="table table-striped">
        <thead>
            <tr><th>Date</th><th>Invoice #</th><th>Patient</th><th>Amount</th><th>Method</th><th>Reference</th></tr>
        </thead>
        <tbody>
            @foreach (var payment in allPayments)
            {
                <tr>
                    <td>@payment.Date.ToString("yyyy-MM-dd HH:mm")</td>
                    <td>@payment.InvoiceId</td>
                    <td>@payment.Invoice.Pet.Name</td>
                    <td>@payment.Amount.ToString("C")</td>
                    <td>@payment.Method</td>
                    <td>@payment.Reference</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private string activeTab = "invoices";
    private List<VetClinic.Data.Invoice> invoices = [];
    private List<VetClinic.Data.Payment> allPayments = [];
    private List<VetClinic.Data.Pet> pets = [];
    private bool showInvoiceForm;
    private bool showPayForm;
    private VetClinic.Data.Invoice? selectedInvoice;
    private InvoiceFormModel invoiceModel = new();
    private PaymentFormModel paymentModel = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        invoices = await Db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.LineItems)
            .Include(i => i.Payments)
            .OrderByDescending(i => i.IssuedDate)
            .ToListAsync();
        allPayments = await Db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Pet)
            .OrderByDescending(p => p.Date)
            .ToListAsync();
    }

    private void ShowCreateInvoice()
    {
        invoiceModel = new InvoiceFormModel();
        invoiceModel.LineItems.Add(new LineItemModel());
        showInvoiceForm = true;
    }

    private void AddLineItem()
    {
        invoiceModel.LineItems.Add(new LineItemModel());
    }

    private async Task SaveInvoice()
    {
        var invoice = new VetClinic.Data.Invoice
        {
            PetId = invoiceModel.PetId,
            Description = invoiceModel.Description,
            IssuedDate = DateTime.UtcNow,
            LineItems = invoiceModel.LineItems.Select(li => new VetClinic.Data.InvoiceLineItem
            {
                Description = li.Description,
                Amount = li.Amount
            }).ToList()
        };
        Db.Invoices.Add(invoice);
        await Db.SaveChangesAsync();
        showInvoiceForm = false;
        await LoadData();
    }

    private void ShowPaymentForm(VetClinic.Data.Invoice invoice)
    {
        selectedInvoice = invoice;
        paymentModel = new PaymentFormModel
        {
            Amount = invoice.Balance,
            Date = DateOnly.FromDateTime(DateTime.Today)
        };
        showPayForm = true;
    }

    private async Task SavePayment()
    {
        if (selectedInvoice == null) return;

        var payment = new VetClinic.Data.Payment
        {
            InvoiceId = selectedInvoice.Id,
            Amount = paymentModel.Amount,
            Method = paymentModel.Method,
            Reference = paymentModel.Reference,
            Date = paymentModel.Date.ToDateTime(TimeOnly.FromDateTime(DateTime.Now))
        };
        Db.Payments.Add(payment);
        await Db.SaveChangesAsync();
        showPayForm = false;
        await LoadData();
    }

    private class InvoiceFormModel
    {
        [System.ComponentModel.DataAnnotations.Range(1, int.MaxValue, ErrorMessage = "Please select a patient.")]
        public int PetId { get; set; }

        public string? Description { get; set; }
        public List<LineItemModel> LineItems { get; set; } = [];
    }

    private class LineItemModel
    {
        public string Description { get; set; } = "";
        public decimal Amount { get; set; }
    }

    private class PaymentFormModel
    {
        [System.ComponentModel.DataAnnotations.Range(0.01, double.MaxValue, ErrorMessage = "Amount must be positive.")]
        public decimal Amount { get; set; }

        public VetClinic.Data.PaymentMethod Method { get; set; }
        public string? Reference { get; set; }
        public DateOnly Date { get; set; } = DateOnly.FromDateTime(DateTime.Today);
    }
}

