@inject VetClinic.Data.ApplicationDbContext Db
@using Microsoft.EntityFrameworkCore

<PageTitle>Patients</PageTitle>

<h1>Patient Records</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by pet or owner name..."
               @bind="searchTerm" @bind:event="oninput" @bind:after="Search" />
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-primary" @onclick="ShowRegisterForm">
