toolArgs.file_text:
@page "/appointments"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject VetClinic.Data.ApplicationDbContext Db
@using Microsoft.EntityFrameworkCore

<PageTitle>Appointments</PageTitle>

<h1>Appointment Scheduling</h1>

<div class="row mb-3">
    <div class="col-md-3">
        <label class="form-label">View Date</label>
        <input type="date" class="form-control" @bind="selectedDate" @bind:after="LoadAppointments" />
    </div>
    <div class="col-md-3 d-flex align-items-end">
        <button class="btn btn-primary" @onclick="ShowCreateForm">+ New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-4">
        <div class="card-header">
            <h5>@(editingAppointment == null ? "Schedule Appointment" : "Edit Appointment")</h5>
        </div>
        <div class="card-body">
            <EditForm Model="formModel" OnValidSubmit="SaveAppointment" FormName="appointmentForm">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="row mb-3">
                    <div class="col-md-4">
                        <label class="form-label">Patient</label>
                        <InputSelect class="form-select" @bind-Value="formModel.PetId">
                            <option value="0">-- Select Patient --</option>
                            @foreach (var pet in pets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Veterinarian</label>
                        <InputText class="form-control" @bind-Value="formModel.Veterinarian" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="formModel.Reason" />
                    </div>
                </div>
                <div class="row mb-3">
                    <div class="col-md-3">
                        <label class="form-label">Date</label>
                        <InputDate class="form-control" @bind-Value="formModel.Date" @bind-Value:after="CheckAvailability" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Start Time</label>
                        <InputSelect class="form-select" @bind-Value="formModel.StartTime" @bind-Value:after="CheckAvailability">
                            @foreach (var slot in timeSlots)
                            {
                                <option value="@slot">@slot.ToString("HH:mm")</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Duration (min)</label>
                        <InputSelect class="form-select" @bind-Value="formModel.DurationMinutes">
                            <option value="15">15 min</option>
                            <option value="30">30 min</option>
                            <option value="45">45 min</option>
                            <option value="60">60 min</option>
                        </InputSelect>
                    </div>
                </div>
                <div class="mb-3">
                    <label class="form-label">Notes</label>
                    <InputTextArea class="form-control" rows="2" @bind-Value="formModel.Notes" />
                </div>

                @if (!string.IsNullOrEmpty(availabilityMessage))
                {
                    <div class="alert @(isSlotAvailable ? "alert-success" : "alert-warning") py-2">
                        @availabilityMessage
                    </div>
                }

                <button type="submit" class="btn btn-success me-2" disabled="@(!isSlotAvailable)">Save</button>
                <button type="button" class="btn btn-secondary" @onclick="() => showForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

<h4>Schedule for @selectedDate.ToString("dddd, MMMM d, yyyy")</h4>

<div class="row">
    <div class="col-md-8">
        <table class="table table-bordered">
            <thead class="table-light">
                <tr><th style="width:120px">Time</th><th>Patient</th><th>Reason</th><th>Vet</th><th>Status</th><th>Actions</th></tr>
            </thead>
            <tbody>
                @if (dayAppointments.Any())
                {
                    @foreach (var apt in dayAppointments)
                    {
                        <tr class="@GetRowClass(apt.Status)">
                            <td>@apt.StartTime.ToString("HH:mm")–@apt.EndTime.ToString("HH:mm")</td>
                            <td>@apt.Pet.Name</td>
                            <td>@apt.Reason</td>
                            <td>@apt.Veterinarian</td>
                            <td><span class="badge bg-@GetStatusColor(apt.Status)">@apt.Status</span></td>
                            <td>
                                @if (apt.Status == VetClinic.Data.AppointmentStatus.Scheduled)
                                {
                                    <button class="btn btn-sm btn-outline-primary me-1" @onclick="() => Reschedule(apt)">Reschedule</button>
                                    <button class="btn btn-sm btn-outline-success me-1" @onclick="() => Complete(apt)">Complete</button>
                                    <button class="btn btn-sm btn-outline-danger" @onclick="() => Cancel(apt)">Cancel</button>
                                }
                            </td>
                        </tr>
                    }
                }
                else
                {
                    <tr><td colspan="6" class="text-center text-muted">No appointments for this day.</td></tr>
                }
            </tbody>
        </table>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-header"><h6>Available Slots</h6></div>
            <div class="card-body">
                @foreach (var slot in GetAvailableSlots())
                {
                    <span class="badge bg-success me-1 mb-1">@slot.ToString("HH:mm")</span>
                }
                @if (!GetAvailableSlots().Any())
                {
                    <span class="text-muted">No available slots.</span>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private DateTime selectedDate = DateTime.Today;
    private List<VetClinic.Data.Appointment> dayAppointments = [];
    private List<VetClinic.Data.Pet> pets = [];
    private bool showForm;
    private VetClinic.Data.Appointment? editingAppointment;
    private AppointmentFormModel formModel = new();
    private string availabilityMessage = "";
    private bool isSlotAvailable = true;

    private static readonly TimeOnly clinicOpen = new(8, 0);
    private static readonly TimeOnly clinicClose = new(18, 0);
    private List<TimeOnly> timeSlots = [];

    protected override async Task OnInitializedAsync()
    {
        GenerateTimeSlots();
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        await LoadAppointments();
    }

    private void GenerateTimeSlots()
    {
        timeSlots = [];
        var current = clinicOpen;
        while (current < clinicClose)
        {
            timeSlots.Add(current);
            current = current.AddMinutes(30);
        }
    }

    private async Task LoadAppointments()
    {
        dayAppointments = await Db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime.Date == selectedDate.Date)
            .OrderBy(a => a.StartTime)
            .ToListAsync();
    }

    private void ShowCreateForm()
    {
        editingAppointment = null;
        formModel = new AppointmentFormModel
        {
            Date = DateOnly.FromDateTime(selectedDate),
            StartTime = clinicOpen,
            DurationMinutes = 30
        };
        showForm = true;
        availabilityMessage = "";
        isSlotAvailable = true;
    }

    private void Reschedule(VetClinic.Data.Appointment apt)
    {
        editingAppointment = apt;
        formModel = new AppointmentFormModel
        {
            PetId = apt.PetId,
            Date = DateOnly.FromDateTime(apt.StartTime),
            StartTime = TimeOnly.FromDateTime(apt.StartTime),
            DurationMinutes = (int)(apt.EndTime - apt.StartTime).TotalMinutes,
            Reason = apt.Reason,
            Veterinarian = apt.Veterinarian ?? "",
            Notes = apt.Notes
        };
        showForm = true;
        isSlotAvailable = true;
        availabilityMessage = "";
    }

    private async Task Complete(VetClinic.Data.Appointment apt)
    {
        apt.Status = VetClinic.Data.AppointmentStatus.Completed;
        await Db.SaveChangesAsync();
        await LoadAppointments();
    }

    private async Task Cancel(VetClinic.Data.Appointment apt)
    {
        apt.Status = VetClinic.Data.AppointmentStatus.Cancelled;
        await Db.SaveChangesAsync();
        await LoadAppointments();
    }

    private async Task CheckAvailability()
    {
        var start = formModel.Date.ToDateTime(formModel.StartTime);
        var end = start.AddMinutes(formModel.DurationMinutes);

        var conflicts = await Db.Appointments
            .Where(a => a.StartTime.Date == start.Date
                && a.Status == VetClinic.Data.AppointmentStatus.Scheduled
                && a.StartTime < end && a.EndTime > start
                && (editingAppointment == null || a.Id != editingAppointment.Id))
            .CountAsync();

        if (conflicts > 0)
        {
            isSlotAvailable = false;
            availabilityMessage = $"⚠️ Conflict: {conflicts} existing appointment(s) overlap this time slot.";
        }
        else
        {
            isSlotAvailable = true;
            availabilityMessage = "✓ Time slot is available.";
        }
    }

    private async Task SaveAppointment()
    {
        var start = formModel.Date.ToDateTime(formModel.StartTime);
        var end = start.AddMinutes(formModel.DurationMinutes);

        if (editingAppointment != null)
        {
            editingAppointment.PetId = formModel.PetId;
            editingAppointment.StartTime = start;
            editingAppointment.EndTime = end;
            editingAppointment.Reason = formModel.Reason;
            editingAppointment.Veterinarian = formModel.Veterinarian;
            editingAppointment.Notes = formModel.Notes;
        }
        else
        {
            var apt = new VetClinic.Data.Appointment
            {
                PetId = formModel.PetId,
                StartTime = start,
                EndTime = end,
                Reason = formModel.Reason,
                Veterinarian = formModel.Veterinarian,
                Notes = formModel.Notes,
                Status = VetClinic.Data.AppointmentStatus.Scheduled
            };
            Db.Appointments.Add(apt);
        }

        await Db.SaveChangesAsync();
        showForm = false;
        selectedDate = formModel.Date.ToDateTime(TimeOnly.MinValue);
        await LoadAppointments();
    }

    private List<TimeOnly> GetAvailableSlots()
    {
        var available = new List<TimeOnly>();
        foreach (var slot in timeSlots)
        {
            var slotStart = selectedDate.Date + slot.ToTimeSpan();
            var slotEnd = slotStart.AddMinutes(30);
            var hasConflict = dayAppointments.Any(a =>
                a.Status == VetClinic.Data.AppointmentStatus.Scheduled &&
                a.StartTime < slotEnd && a.EndTime > slotStart);
            if (!hasConflict)
                available.Add(slot);
        }
        return available;
    }

    private string GetStatusColor(VetClinic.Data.AppointmentStatus status) => status switch
    {
        VetClinic.Data.AppointmentStatus.Scheduled => "primary",
        VetClinic.Data.AppointmentStatus.Completed => "success",
