+        {
+            isSlotAvailable = true;
+            availabilityMessage = "✓ Time slot is available.";
+        }
+    }
+
+    private async Task SaveAppointment()
+    {
+        var start = formModel.Date.ToDateTime(formModel.StartTime);
+        var end = start.AddMinutes(formModel.DurationMinutes);
+
+        if (editingAppointment != null)
+        {
+            editingAppointment.PetId = formModel.PetId;
+            editingAppointment.StartTime = start;
+            editingAppointment.EndTime = end;
+            editingAppointment.Reason = formModel.Reason;
+            editingAppointment.Veterinarian = formModel.Veterinarian;
+            editingAppointment.Notes = formModel.Notes;
+        }
+        else
+        {
+            var apt = new VetClinic.Data.Appointment
+            {
+                PetId = formModel.PetId,
+                StartTime = start,
+                EndTime = end,
+                Reason = formModel.Reason,
+                Veterinarian = formModel.Veterinarian,
+                Notes = formModel.Notes,
+                Status = VetClinic.Data.AppointmentStatus.Scheduled
+            };
+            Db.Appointments.Add(apt);
+        }
+
+        await Db.SaveChangesAsync();
+        showForm = false;
+        selectedDate = formModel.Date.ToDateTime(TimeOnly.MinValue);
+        await LoadAppointments();
+    }
+
+    private List<TimeOnly> GetAvailableSlots()
+    {
+        var available = new List<TimeOnly>();
+        foreach (var slot in timeSlots)
+        {
+            var slotStart = selectedDate.Date + slot.ToTimeSpan();
+            var slotEnd = slotStart.AddMinutes(30);
+            var hasConflict = dayAppointments.Any(a =>
+                a.Status == VetClinic.Data.AppointmentStatus.Scheduled &&
+                a.StartTime < slotEnd && a.EndTime > slotStart);
+            if (!hasConflict)
+                available.Add(slot);
+        }
+        return available;
+    }
+
