+        VetClinic.Data.AppointmentStatus.Cancelled => "secondary",
+        _ => "light"
+    };
+
+    private string GetRowClass(VetClinic.Data.AppointmentStatus status) => status switch
+    {
+        VetClinic.Data.AppointmentStatus.Cancelled => "table-secondary text-decoration-line-through",
+        VetClinic.Data.AppointmentStatus.Completed => "table-success",
+        _ => ""
+    };
