+    </li>
+</ul>
+
+@if (activeTab == "invoices")
+{
+    <div class="mb-3">
+        <button class="btn btn-primary" @onclick="ShowCreateInvoice">+ New Invoice</button>
+    </div>
+
+    @if (showInvoiceForm)
+    {
+        <div class="card mb-4">
+            <div class="card-header"><h5>Create Invoice</h5></div>
+            <div class="card-body">
+                <EditForm Model="invoiceModel" OnValidSubmit="SaveInvoice" FormName="invoiceForm">
+                    <DataAnnotationsValidator />
+                    <ValidationSummary class="text-danger" />
+
+                    <div class="row mb-3">
+                        <div class="col-md-4">
+                            <label class="form-label">Patient</label>
+                            <InputSelect class="form-select" @bind-Value="invoiceModel.PetId">
+                                <option value="0">-- Select Patient --</option>
+                                @foreach (var pet in pets)
+                                {
+                                    <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
+                                }
+                            </InputSelect>
+                        </div>
+                        <div class="col-md-8">
+                            <label class="form-label">Description</label>
+                            <InputText class="form-control" @bind-Value="invoiceModel.Description" />
+                        </div>
+                    </div>
+
+                    <h6>Line Items</h6>
+                    @for (int i = 0; i < invoiceModel.LineItems.Count; i++)
+                    {
+                        var idx = i;
+                        <div class="row mb-2">
+                            <div class="col-md-7">
+                                <input class="form-control" placeholder="Description" @bind="invoiceModel.LineItems[idx].Description" />
+                            </div>
+                            <div class="col-md-3">
+                                <input type="number" step="0.01" class="form-control" placeholder="Amount" @bind="invoiceModel.LineItems[idx].Amount" />
+                            </div>
+                            <div class="col-md-2">
+                                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => invoiceModel.LineItems.RemoveAt(idx)">Remove</button>
+                            </div>
+                        </div>
+                    }
+                    <button type="button" class="btn btn-outline-secondary btn-sm mb-3" @onclick="AddLineItem">+ Add Line Item</button>
+
+                    <div class="mb-3">
+                        <strong>Total: @invoiceModel.LineItems.Sum(li => li.Amount).ToString("C")</strong>
+                    </div>
+
+                    <button type="submit" class="btn btn-success me-2">Create Invoice</button>
+                    <button type="button" class="btn btn-secondary" @onclick="() => showInvoiceForm = false">Cancel</button>
+                </EditForm>
+            </div>
+        </div>
+    }
+
+    <table class="table table-hover">
+        <thead>
+            <tr><th>#</th><th>Date</th><th>Patient</th><th>Description</th><th>Total</th><th>Paid</th><th>Balance</th><th>Status</th><th>Actions</th></tr>
+        </thead>
+        <tbody>
+            @foreach (var inv in invoices)
+            {
+                <tr>
+                    <td>@inv.Id</td>
+                    <td>@inv.IssuedDate.ToString("yyyy-MM-dd")</td>
+                    <td>@inv.Pet.Name</td>
+                    <td>@inv.Description</td>
+                    <td>@inv.Total.ToString("C")</td>
+                    <td>@inv.AmountPaid.ToString("C")</td>
+                    <td>@inv.Balance.ToString("C")</td>
+                    <td>
+                        @if (inv.IsPaid)
+                        {
+                            <span class="badge bg-success">Paid</span>
+                        }
+                        else
+                        {
+                            <span class="badge bg-warning">Outstanding</span>
+                        }
+                    </td>
+                    <td>
+                        @if (!inv.IsPaid)
+                        {
+                            <button class="btn btn-sm btn-outline-success" @onclick="() => ShowPaymentForm(inv)">Record Payment</button>
+                        }
+                    </td>
+                </tr>
+            }
+        </tbody>
+    </table>
+
+    @if (showPayForm && selectedInvoice != null)
+    {
+        <div class="card mb-4">
+            <div class="card-header"><h5>Record Payment for Invoice #@selectedInvoice.Id</h5></div>
+            <div class="card-body">
+                <EditForm Model="paymentModel" OnValidSubmit="SavePayment" FormName="paymentForm">
+                    <DataAnnotationsValidator />
+                    <div class="row mb-3">
+                        <div class="col-md-3">
+                            <label class="form-label">Amount (Balance: @selectedInvoice.Balance.ToString("C"))</label>
+                            <InputNumber class="form-control" @bind-Value="paymentModel.Amount" />
+                        </div>
+                        <div class="col-md-3">
+                            <label class="form-label">Method</label>
+                            <InputSelect class="form-select" @bind-Value="paymentModel.Method">
+                                @foreach (var method in Enum.GetValues<VetClinic.Data.PaymentMethod>())
+                                {
+                                    <option value="@method">@method</option>
+                                }
+                            </InputSelect>
+                        </div>
+                        <div class="col-md-3">
+                            <label class="form-label">Reference</label>
+                            <InputText class="form-control" @bind-Value="paymentModel.Reference" />
+                        </div>
+                        <div class="col-md-3">
+                            <label class="form-label">Date</label>
+                            <InputDate class="form-control" @bind-Value="paymentModel.Date" />
+                        </div>
+                    </div>
+                    <button type="submit" class="btn btn-success me-2">Process Payment</button>
+                    <button type="button" class="btn btn-secondary" @onclick="() => showPayForm = false">Cancel</button>
+                </EditForm>
+            </div>
+        </div>
+    }
+}
+else
+{
+    <h4>Payment History</h4>
+    <table class="table table-striped">
+        <thead>
+            <tr><th>Date</th><th>Invoice #</th><th>Patient</th><th>Amount</th><th>Method</th><th>Reference</th></tr>
+        </thead>
+        <tbody>
+            @foreach (var payment in allPayments)
+            {
+                <tr>
+                    <td>@payment.Date.ToString("yyyy-MM-dd HH:mm")</td>
+                    <td>@payment.InvoiceId</td>
+                    <td>@payment.Invoice.Pet.Name</td>
+                    <td>@payment.Amount.ToString("C")</td>
+                    <td>@payment.Method</td>
+                    <td>@payment.Reference</td>
+                </tr>
+            }
+        </tbody>
+    </table>
+}
+
+@code {
+    private string activeTab = "invoices";
+    private List<VetClinic.Data.Invoice> invoices = [];
+    private List<VetClinic.Data.Payment> allPayments = [];
+    private List<VetClinic.Data.Pet> pets = [];
+    private bool showInvoiceForm;
+    private bool showPayForm;
+    private VetClinic.Data.Invoice? selectedInvoice;
+    private InvoiceFormModel invoiceModel = new();
+    private PaymentFormModel paymentModel = new();
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadData();
+    }
+
+    private async Task LoadData()
+    {
+        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
+        invoices = await Db.Invoices
+            .Include(i => i.Pet).ThenInclude(p => p.Owner)
+            .Include(i => i.LineItems)
+            .Include(i => i.Payments)
+            .OrderByDescending(i => i.IssuedDate)
+            .ToListAsync();
+        allPayments = await Db.Payments
+            .Include(p => p.Invoice).ThenInclude(i => i.Pet)
+            .OrderByDescending(p => p.Date)
+            .ToListAsync();
+    }
+
+    private void ShowCreateInvoice()
+    {
+        invoiceModel = new InvoiceFormModel();
+        invoiceModel.LineItems.Add(new LineItemModel());
+        showInvoiceForm = true;
+    }
+
+    private void AddLineItem()
+    {
+        invoiceModel.LineItems.Add(new LineItemModel());
+    }
+
+    private async Task SaveInvoice()
+    {
+        var invoice = new VetClinic.Data.Invoice
+        {
+            PetId = invoiceModel.PetId,
+            Description = invoiceModel.Description,
+            IssuedDate = DateTime.UtcNow,
+            LineItems = invoiceModel.LineItems.Select(li => new VetClinic.Data.InvoiceLineItem
+            {
+                Description = li.Description,
+                Amount = li.Amount
+            }).ToList()
+        };
+        Db.Invoices.Add(invoice);
+        await Db.SaveChangesAsync();
+        showInvoiceForm = false;
+        await LoadData();
+    }
+
+    private void ShowPaymentForm(VetClinic.Data.Invoice invoice)
+    {
+        selectedInvoice = invoice;
+        paymentModel = new PaymentFormModel
+        {
+            Amount = invoice.Balance,
+            Date = DateOnly.FromDateTime(DateTime.Today)
+        };
+        showPayForm = true;
+    }
+
+    private async Task SavePayment()
+    {
+        if (selectedInvoice == null) return;
+
+        var payment = new VetClinic.Data.Payment
+        {
+            InvoiceId = selectedInvoice.Id,
+            Amount = paymentModel.Amount,
+            Method = paymentModel.Method,
+            Reference = paymentModel.Reference,
+            Date = paymentModel.Date.ToDateTime(TimeOnly.FromDateTime(DateTime.Now))
+        };
+        Db.Payments.Add(payment);
+        await Db.SaveChangesAsync();
+        showPayForm = false;
+        await LoadData();
+    }
+
+    private class InvoiceFormModel
+    {
+        [System.ComponentModel.DataAnnotations.Range(1, int.MaxValue, ErrorMessage = "Please select a patient.")]
+        public int PetId { get; set; }
+
+        public string? Description { get; set; }
+        public List<LineItemModel> LineItems { get; set; } = [];
+    }
+
+    private class LineItemModel
+    {
+        public string Description { get; set; } = "";
+        public decimal Amount { get; set; }
+    }
+
+    private class PaymentFormModel
+    {
+        [System.ComponentModel.DataAnnotations.Range(0.01, double.MaxValue, ErrorMessage = "Amount must be positive.")]
+        public decimal Amount { get; set; }
+
+        public VetClinic.Data.PaymentMethod Method { get; set; }
+        public string? Reference { get; set; }
+        public DateOnly Date { get; set; } = DateOnly.FromDateTime(DateTime.Today);
+    }
+}
